const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let arr = [];
readline.on('line', line => {
    if (i == 0) {
        n = parseInt(line);
    } else {
        arr = line.split(' ').map(num => parseInt(num));
        arr.sort((a, b) => a - b);
        let max_count = 0, count = 0;
        for (let j = 0; j < n; j++) {
            if (j == 0 || arr[j] != arr[j-1]) {
                count = 1;
            } else {
                count++;
            }
            if (count > max_count) {
                max_count = count;
            }
        }
        console.log(n - max_count);
        readline.close();
    }
    i++;
});

